import{_ as e,c as i,o as s,a1 as l}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Funciones de la Plataforma: Comandos Principales y Gestión de Habilidades | OpenSkills","description":"Aprende las funcionalidades de la plataforma OpenSkills, domina comandos y operaciones principales como instalar, listar, actualizar y eliminar habilidades, entiende las diferencias entre gestión global y de proyecto.","frontmatter":{"title":"Funciones de la Plataforma: Comandos Principales y Gestión de Habilidades | OpenSkills","sidebarTitle":"Dominar las Operaciones Principales","subtitle":"Funciones de la Plataforma: Comandos Principales y Gestión de Habilidades | OpenSkills","description":"Aprende las funcionalidades de la plataforma OpenSkills, domina comandos y operaciones principales como instalar, listar, actualizar y eliminar habilidades, entiende las diferencias entre gestión global y de proyecto.","order":2},"headers":[],"relativePath":"es/numman-ali/openskills/platforms/index.md","filePath":"es/numman-ali/openskills/platforms/index.md"}'),d={name:"es/numman-ali/openskills/platforms/index.md"};function t(o,a,n,r,c,p){return s(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="funciones-de-la-plataforma" tabindex="-1">Funciones de la Plataforma <a class="header-anchor" href="#funciones-de-la-plataforma" aria-label="Permalink to &quot;Funciones de la Plataforma&quot;">​</a></h1><p>Este capítulo profundiza en los comandos principales de OpenSkills CLI y las funcionalidades de gestión de habilidades, ayudándote a pasar de &quot;saber usar&quot; a &quot;dominar&quot;.</p><h2 id="requisitos-previos" tabindex="-1">Requisitos Previos <a class="header-anchor" href="#requisitos-previos" aria-label="Permalink to &quot;Requisitos Previos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Antes de Empezar</p><p>Antes de estudiar este capítulo, asegúrate de haber completado el capítulo de <a href="./../start/">Inicio Rápido</a>, especialmente:</p><ul><li><a href="./../start/installation/">Instalar OpenSkills</a>: Habrás instalado con éxito OpenSkills CLI</li><li><a href="./../start/first-skill/">Instalar la Primera Habilidad</a>: Entiendes el flujo básico de instalación de habilidades</li></ul></div><h2 id="contenido-del-capitulo" tabindex="-1">Contenido del Capítulo <a class="header-anchor" href="#contenido-del-capitulo" aria-label="Permalink to &quot;Contenido del Capítulo&quot;">​</a></h2><p>Este capítulo contiene 6 temas, cubriendo todas las funcionalidades principales de OpenSkills:</p><h3 id="explicacion-de-comandos" tabindex="-1"><a href="./cli-commands/">Explicación de Comandos</a> <a class="header-anchor" href="#explicacion-de-comandos" aria-label="Permalink to &quot;[Explicación de Comandos](./cli-commands/)&quot;">​</a></h3><p>Presentación completa de los 7 comandos, parámetros y flags, proporcionando una tabla de referencia rápida de comandos. Adecuado para usuarios que necesitan buscar rápidamente el uso de comandos.</p><h3 id="fuentes-de-instalacion-detalladas" tabindex="-1"><a href="./install-sources/">Fuentes de Instalación Detalladas</a> <a class="header-anchor" href="#fuentes-de-instalacion-detalladas" aria-label="Permalink to &quot;[Fuentes de Instalación Detalladas](./install-sources/)&quot;">​</a></h3><p>Explicación detallada de tres fuentes de instalación: repositorios de GitHub, rutas locales y repositorios Git privados. Escenarios de aplicación, formatos de comandos y consideraciones para cada método.</p><h3 id="instalacion-global-vs-instalacion-local-del-proyecto" tabindex="-1"><a href="./global-vs-project/">Instalación Global vs Instalación Local del Proyecto</a> <a class="header-anchor" href="#instalacion-global-vs-instalacion-local-del-proyecto" aria-label="Permalink to &quot;[Instalación Global vs Instalación Local del Proyecto](./global-vs-project/)&quot;">​</a></h3><p>Explica las diferencias entre la instalación <code>--global</code> y la predeterminada (local del proyecto), ayudándote a elegir la ubicación de instalación adecuada y a entender las reglas de prioridad de búsqueda de habilidades.</p><h3 id="listar-habilidades-instaladas" tabindex="-1"><a href="./list-skills/">Listar Habilidades Instaladas</a> <a class="header-anchor" href="#listar-habilidades-instaladas" aria-label="Permalink to &quot;[Listar Habilidades Instaladas](./list-skills/)&quot;">​</a></h3><p>Te enseña a usar el comando <code>list</code> para ver las habilidades instaladas, entendiendo el significado de las etiquetas de ubicación <code>(project)</code> y <code>(global)</code>.</p><h3 id="actualizar-habilidades" tabindex="-1"><a href="./update-skills/">Actualizar Habilidades</a> <a class="header-anchor" href="#actualizar-habilidades" aria-label="Permalink to &quot;[Actualizar Habilidades](./update-skills/)&quot;">​</a></h3><p>Te guía para usar el comando <code>update</code> para actualizar las habilidades instaladas, soportando actualización completa y actualización de habilidades específicas, manteniendo las habilidades sincronizadas con el repositorio fuente.</p><h3 id="eliminar-habilidades" tabindex="-1"><a href="./remove-skills/">Eliminar Habilidades</a> <a class="header-anchor" href="#eliminar-habilidades" aria-label="Permalink to &quot;[Eliminar Habilidades](./remove-skills/)&quot;">​</a></h3><p>Presenta dos métodos de eliminación: comando interactivo <code>manage</code> y comando de automatización <code>remove</code>, ayudándote a gestionar tu biblioteca de habilidades de manera eficiente.</p><h2 id="ruta-de-aprendizaje" tabindex="-1">Ruta de Aprendizaje <a class="header-anchor" href="#ruta-de-aprendizaje" aria-label="Permalink to &quot;Ruta de Aprendizaje&quot;">​</a></h2><p>Según tus necesidades, elige la ruta de aprendizaje adecuada:</p><h3 id="ruta-a-aprendizaje-sistematico-recomendado-para-principiantes" tabindex="-1">Ruta A: Aprendizaje Sistemático (Recomendado para Principiantes) <a class="header-anchor" href="#ruta-a-aprendizaje-sistematico-recomendado-para-principiantes" aria-label="Permalink to &quot;Ruta A: Aprendizaje Sistemático (Recomendado para Principiantes)&quot;">​</a></h3><p>Estudia todo el contenido en orden, construyendo un sistema de conocimiento completo:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Explicación de Comandos → Fuentes de Instalación → Global vs Proyecto → Listar Habilidades → Actualizar Habilidades → Eliminar Habilidades</span></span></code></pre></div><h3 id="ruta-b-consulta-bajo-demanda" tabindex="-1">Ruta B: Consulta Bajo Demanda <a class="header-anchor" href="#ruta-b-consulta-bajo-demanda" aria-label="Permalink to &quot;Ruta B: Consulta Bajo Demanda&quot;">​</a></h3><p>Salta directamente según la tarea actual:</p><table tabindex="0"><thead><tr><th>Qué Quieres Hacer</th><th>Lee Este Artículo</th></tr></thead><tbody><tr><td>Buscar el uso de un comando específico</td><td><a href="./cli-commands/">Explicación de Comandos</a></td></tr><tr><td>Instalar habilidades desde repositorios privados</td><td><a href="./install-sources/">Fuentes de Instalación Detalladas</a></td></tr><tr><td>Decidir entre instalación global o del proyecto</td><td><a href="./global-vs-project/">Global vs Proyecto</a></td></tr><tr><td>Ver qué habilidades están instaladas</td><td><a href="./list-skills/">Listar Habilidades Instaladas</a></td></tr><tr><td>Actualizar habilidades a la última versión</td><td><a href="./update-skills/">Actualizar Habilidades</a></td></tr><tr><td>Limpiar habilidades no utilizadas</td><td><a href="./remove-skills/">Eliminar Habilidades</a></td></tr></tbody></table><h2 id="siguientes-pasos" tabindex="-1">Siguientes Pasos <a class="header-anchor" href="#siguientes-pasos" aria-label="Permalink to &quot;Siguientes Pasos&quot;">​</a></h2><p>Al completar este capítulo, ya has dominado las habilidades de uso diario de OpenSkills. Luego puedes:</p><ul><li><strong><a href="./../advanced/">Funciones Avanzadas</a></strong>: Aprende funciones avanzadas como el modo Universal, rutas de salida personalizadas, enlaces simbólicos, creación de habilidades personalizadas, etc.</li><li><strong><a href="./../faq/">Preguntas Frecuentes</a></strong>: Consulta las FAQ y la guía de solución de problemas cuando encuentres problemas</li></ul>',29)])])}const h=e(d,[["render",t]]);export{m as __pageData,h as default};
